import { useState } from "react";
import { useNavigate, Link } from "react-router-dom";

function Register() {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    password: "",
    confirmPassword: "",
  });
  const [error, setError] = useState("");

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleRegister = (e) => {
    e.preventDefault();
    setError("");

    if (!form.name || !form.email || !form.phone || !form.password || !form.confirmPassword) {
      setError("Please fill in all fields.");
      return;
    }

    if (form.password !== form.confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    // ── Django REST API call (uncomment when backend is ready) ──
    // fetch("/api/auth/register/", {
    //   method: "POST",
    //   headers: { "Content-Type": "application/json" },
    //   body: JSON.stringify({
    //     name: form.name,
    //     email: form.email,
    //     phone: form.phone,
    //     password: form.password,
    //   }),
    // })
    //   .then((res) => res.json())
    //   .then((data) => {
    //     if (data.token) {
    //       localStorage.setItem("token", data.token);
    //       navigate("/");
    //     }
    //   })
    //   .catch((err) => setError("Registration failed. Try again."));

    // Remove this navigate once backend is connected:
    navigate("/");
  };

  return (
    <div className="loginPageWrapper">
      <div className="loginBox">
        <h2>Create Account</h2>
        <p>Sign up to start finding the best deals.</p>

        <form className="loginForm" onSubmit={handleRegister}>
          <input
            type="text"
            name="name"
            placeholder="Full name"
            value={form.name}
            onChange={handleChange}
          />

          <input
            type="email"
            name="email"
            placeholder="Email address"
            value={form.email}
            onChange={handleChange}
          />

          <input
            type="tel"
            name="phone"
            placeholder="Phone number"
            value={form.phone}
            onChange={handleChange}
          />

          <input
            type="password"
            name="password"
            placeholder="Password"
            value={form.password}
            onChange={handleChange}
          />

          <input
            type="password"
            name="confirmPassword"
            placeholder="Confirm password"
            value={form.confirmPassword}
            onChange={handleChange}
          />

          {error && <p style={{ color: "#ff3b30", fontSize: "14px", margin: 0 }}>{error}</p>}

          <button type="submit" className="loginBtn">
            Register
          </button>
        </form>

        <p style={{ marginTop: "16px", fontSize: "14px", color: "#6e6e73" }}>
          Already have an account?{" "}
          <Link to="/login" style={{ color: "#0071e3", fontWeight: 600 }}>
            Login
          </Link>
        </p>
      </div>
    </div>
  );
}

export default Register;
